    "about.title": "プロフェッショナルな建設積算、無料・オープンソース",
    "about.who.architects": "建築士・エンジニア",
    "about.who.contractors": "総合建設業者",
    "about.who.developers": "不動産デベロッパー",
    "about.who.estimators": "積算士",
    "about.who.freelancers": "フリーランスコンサルタント",
    "about.who.pm": "プロジェクトマネージャー",
